document.addEventListener('DOMContentLoaded',function(){const mainHeader=document.getElementById('df-main-header');if(mainHeader){window.addEventListener('scroll',function(){if(window.scrollY>10){mainHeader.classList.add('is-scrolled')}else{mainHeader.classList.remove('is-scrolled')}})}
const megaMenuItems=document.querySelectorAll('.menu-item[class*="mega-"]');const megaWrapper=document.querySelector('.df-mega-wrapper');if(megaMenuItems.length>0&&megaWrapper){let activeTimeout;megaMenuItems.forEach(function(item){const slugClass=Array.from(item.classList).find(function(cls){return cls.startsWith('mega-')});if(!slugClass)return;item.addEventListener('mouseenter',function(){if(window.innerWidth>=980){clearTimeout(activeTimeout);handleMegaMenuOpen(slugClass)}});item.addEventListener('mouseleave',function(){if(window.innerWidth>=980){activeTimeout=setTimeout(function(){handleMegaMenuClose()},300)}});var link=item.querySelector('a');if(link){link.addEventListener('click',function(e){if(window.innerWidth<980||window.matchMedia('(hover: none)').matches){e.preventDefault();if(item.classList.contains('df-mega-active')){handleMegaMenuClose()}else{handleMegaMenuOpen(slugClass)}}})}});megaWrapper.addEventListener('mouseenter',function(){clearTimeout(activeTimeout)});megaWrapper.addEventListener('mouseleave',function(){activeTimeout=setTimeout(function(){handleMegaMenuClose()},300)});document.addEventListener('click',function(e){if(!e.target.closest('.df-mega-wrapper')&&!e.target.closest('.menu-item[class*="mega-"]')){handleMegaMenuClose()}});function handleMegaMenuClose(){megaWrapper.classList.remove('active');megaWrapper.querySelectorAll('.mega-content').forEach(function(el){el.style.display='none'});megaMenuItems.forEach(function(el){el.classList.remove('df-mega-active')})}
function handleMegaMenuOpen(slug){clearTimeout(activeTimeout);megaMenuItems.forEach(function(el){el.classList.remove('df-mega-active')});var navItem=document.querySelector('.menu-item.'+slug);if(navItem)navItem.classList.add('df-mega-active');megaWrapper.classList.add('active');megaWrapper.querySelectorAll('.mega-content').forEach(function(el){el.style.display='none'});var pane=megaWrapper.querySelector('.mega-content.'+slug);if(pane){pane.style.display='block'}}}
const locationToggle=document.querySelector('.df-location-toggle');if(locationToggle){locationToggle.addEventListener('click',function(){const dropdown=document.querySelector('.df-location');dropdown.classList.toggle('open')});const locationItems=document.querySelectorAll('.df-location-list li');locationItems.forEach(item=>{item.addEventListener('click',function(){const loc=this.dataset.location||"";const d=new Date();d.setTime(d.getTime()+(30*24*60*60*1000));let expires="expires="+d.toUTCString();document.cookie="df_location="+loc+";"+expires+";path=/";location.reload()})});document.addEventListener('click',function(e){if(!e.target.closest('.df-location')){document.querySelector('.df-location').classList.remove('open')}})}
const mobileTrigger=document.getElementById('df-mobile-trigger');const mobilePanel=document.getElementById('df-mobile-panel');const mobileClose=document.getElementById('df-mobile-close');const mobileBackdrop=document.getElementById('df-mobile-backdrop');function openMobilePanel(){mobilePanel&&mobilePanel.classList.add('open');mobileBackdrop&&mobileBackdrop.classList.add('open');document.body.style.overflow='hidden'}
function closeMobilePanel(){mobilePanel&&mobilePanel.classList.remove('open');mobileBackdrop&&mobileBackdrop.classList.remove('open');document.body.style.overflow=''}
if(mobileTrigger)mobileTrigger.addEventListener('click',openMobilePanel);if(mobileClose)mobileClose.addEventListener('click',closeMobilePanel);if(mobileBackdrop)mobileBackdrop.addEventListener('click',closeMobilePanel);const mobileLocToggle=document.querySelector('.df-mobile-loc-toggle');if(mobileLocToggle){const mobileLocList=document.querySelector('.df-mobile-loc-list');const toggleChevron=mobileLocToggle.querySelector('.df-icon-chevron');mobileLocToggle.addEventListener('click',function(){const isOpen=mobileLocList.style.display==='flex';mobileLocList.style.display=isOpen?'none':'flex';if(toggleChevron)toggleChevron.style.transform=isOpen?'':'rotate(180deg)'});document.querySelectorAll('.df-mobile-loc-item').forEach(function(btn){btn.addEventListener('click',function(){const loc=this.dataset.location||'';const d=new Date();d.setTime(d.getTime()+(30*24*60*60*1000));document.cookie='df_location='+loc+';expires='+d.toUTCString()+';path=/';location.reload()})})}
const mobileNavLinks=document.querySelectorAll('.df-mobile-nav-link');const chevronSVG='<svg class="df-mobile-acc-chevron" xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="m6 9 6 6 6-6"/></svg>';mobileNavLinks.forEach(function(link){const href=link.getAttribute('href');const matchingDesktopItem=Array.from(document.querySelectorAll('.menu-item[class*="mega-"] a')).find(function(a){return a.getAttribute('href')===href||a.textContent.trim()===link.textContent.trim()});if(!matchingDesktopItem)return;const parentLi=matchingDesktopItem.closest('.menu-item');if(!parentLi)return;const slugClass=Array.from(parentLi.classList).find(function(cls){return cls.startsWith('mega-')});if(!slugClass)return;link.setAttribute('data-mega-slug',slugClass);const accRow=document.createElement('div');accRow.className='df-mobile-acc-row';const mainLink=link.cloneNode(!0);mainLink.removeAttribute('data-mega-slug');accRow.appendChild(mainLink);const toggleBtn=document.createElement('button');toggleBtn.className='df-mobile-acc-toggle';toggleBtn.innerHTML=chevronSVG;toggleBtn.setAttribute('aria-expanded','false');accRow.appendChild(toggleBtn);const pane=document.createElement('div');pane.className='df-mobile-acc-pane';pane.style.display='none';pane.innerHTML='';link.parentNode.insertBefore(accRow,link);link.parentNode.insertBefore(pane,accRow.nextSibling);link.remove();toggleBtn.addEventListener('click',function(){const isOpen=pane.style.display!=='none';if(isOpen){pane.style.display='none';toggleBtn.setAttribute('aria-expanded','false');toggleBtn.querySelector('.df-mobile-acc-chevron').style.transform=''}else{pane.style.display='block';toggleBtn.setAttribute('aria-expanded','true');toggleBtn.querySelector('.df-mobile-acc-chevron').style.transform='rotate(180deg)';if(!pane.dataset.loaded){pane.innerHTML='<div class="df-mobile-acc-loading">Loading...</div>';const formData=new URLSearchParams();formData.append('action','df_load_mega_menu');formData.append('slug',slugClass);if(typeof df_ajax!=='undefined'){formData.append('security',df_ajax.nonce);fetch(df_ajax.url,{method:'POST',body:formData}).then(function(res){return res.text()}).then(function(html){pane.innerHTML='<div class="df-mobile-acc-content">'+html+'</div>';pane.dataset.loaded='1'}).catch(function(){pane.innerHTML='<div class="df-mobile-acc-loading">Error loading menu.</div>'})}}}})})})
;